import { test, expect } from '@playwright/test';
import { signInAsMember, sendMentionFromOtherUser } from './fixtures';

test.describe('Channel mention notifications — DND silences external surfaces (REQ-002)', () => {
  // Human description (kept OUT of the test() first arg, which is verbatim from YAML):
  // A member in DND sees ONLY the badge increment — no in-app banner, no sound.
  test('test_member_in_dnd_sees_only_badge_increment_no_banner_no_sound', async ({ page }) => {
    const member = await signInAsMember(page, { dnd: 'manual' });
    await page.goto(`/channel/${member.activeChannelId}`);
    await expect(page.locator('[data-test=app-shell]')).toBeVisible();

    const badgeLocator = page.locator('[data-test=unread-badge]');
    const badgeBefore = await badgeLocator.innerText().catch(() => '0');

    await sendMentionFromOtherUser({ to: member, channel: member.activeChannelId, page });

    // Badge increments (REQ-002 glossary: silence retains badge).
    await expect(badgeLocator).not.toHaveText(badgeBefore);
    // In-app banner does NOT appear within the expect timeout.
    await expect(page.locator('[data-test=in-app-banner]')).toBeHidden();
    // Sound surface — assert no sound-fired marker (the app exposes a
    // `[data-test=last-sound-fired]` element for e2e observability).
    await expect(page.locator('[data-test=last-sound-fired]')).toHaveText('');
  });
});
